import { Box, Container, Grid, Paper, TextField, Typography } from '@material-ui/core';
import { AddRounded } from '@material-ui/icons';
import React from 'react';

const CreateQuiz = () => {
  return (
    <Container>
      <Grid container spacing={2}>
        <form>
            <Grid item xs={12}>
              Create Quiz
            </Grid>
            <Grid item xs={12}>
              <Paper>
                <TextField />
                <TextField />
              </Paper>
            </Grid>
            <Grid item xs={12}>
              Questions
            </Grid>
            <Grid item xs={12}>
              Send All
            </Grid>
        </form>
      </Grid>
    </Container >
  );
}

export default CreateQuiz;
